section.artwork:
aid-urn = "urn:aid:" namespace ":" agent-id
namespace = delegated-ns / self-sovereign-ns delegated-ns = dns-label self-sovereign-ns = dns-label *("." dns-label)
agent-id = dns-label dns-label = let-dig *(let-dig-hyp) let-dig / let-dig let-dig = ALPHA / DIGIT let-dig-hyp = ALPHA / DIGIT / "-"

POST /airp/v1/identities Content-Type: application/json
{ "agent_id": "a7f3c2e9", "trust_tier": "sovereign", "hardware_fingerprint": "sha256:a1b2c3d4...", "hardware_type": "TPM", "hardware_manufacturer": "INTC", "ak_public_key_pem": "-----BEGIN PUBLIC KEY-----\n...", "display_name": "My Trading Agent", "operator_email": "ops@example.com" }
201 Created { "urn": "urn:aid:global:a7f3c2e9", "registered_at": "2026-03-23T10:30:00Z", "registrar_code": "1IDCOM" }

GET /airp/v1/hardware/sha256:a1b2c3d4.../check
200 OK { "fingerprint": "sha256:a1b2c3d4...", "bound": false }
-- or, if already bound: --
200 OK { "fingerprint": "sha256:a1b2c3d4...", "bound": true, "bound_to_urn": "urn:aid:global:existing-agent", "bound_at": "2025-12-01T08:00:00Z" }

POST /airp/v1/identities/urn:aid:global:a7f3c2e9/transfer
Content-Type: application/json

{
  "to_registrar_code": "NEWREG",
  "authorization_signature": "<base64 sig from enrolled device>",
  "authorization_nonce": "<nonce from gaining registrar>"
}

200 OK
{
  "urn": "urn:aid:global:a7f3c2e9",
  "registrar_code": "NEWREG",
  "transferred_at": "2026-04-15T14:00:00Z"
}
